 14	import MetadataLabels from '@kubevirt-utils/components/MetadataLabels/MetadataLabels';
 15	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 16	import OwnerDetailsItem from '@kubevirt-utils/components/OwnerDetailsItem/OwnerDetailsItem';
