 20	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 21	import {
 22	  DEFAULT_INSTANCETYPE_LABEL,
 23	  DEFAULT_PREFERENCE_LABEL,
 24	} from '@kubevirt-utils/resources/bootableresources/constants';
