 36	export const DataSourceDetailsGrid: React.FC<DataSourceDetailsGridProps> = ({ dataSource }) => {
 37	  const { t } = useKubevirtTranslation();
 38	  const { createModal } = useModal();
 39	  const dataImportCron = getDataSourceCronJob(dataSource);
 40	  const { name: pvcSourceName, namespace: pvcSourceNamespace } =
 41	    dataSource?.spec?.source?.pvc || {};
