 93	                      resource: dataSource,
 94	                    })
 95	                  }
 96	                  isOpen={isOpen}
 97	                  obj={dataSource}
 98	                  onClose={onClose}
 99	                />
100	              ))
101	            }
102	            breadcrumb="DataSource.metadata.labels"
103	            data-test-id={`${dataSource?.metadata?.name}-labels`}
104	            descriptionHeader={t('Labels')}
105	            isEdit
106	            isPopover
107	            moreInfoURL={documentationURL.LABELS}
108	            showEditOnTitle
109	          />
110	          <VirtualMachineDescriptionItem
111	            // body-content text copied from: https://github.com/kubevirt-ui/kubevirt-api/blob/main/containerized-data-importer/models/V1ObjectMeta.ts#L32
112	            bodyContent={t(
113	              'Annotations is an unstructured key value map stored with a resource that may be set by external tools to store and retrieve arbitrary metadata. They are not queryable and should be preserved when modifying objects. ',
114	            )}
115	            descriptionData={
116	              <DataSourceAnnotations annotations={dataSource?.metadata?.annotations} />
117	            }
118	            onEditClick={() =>
119	              createModal(({ isOpen, onClose }) => (
120	                <AnnotationsModal
121	                  onSubmit={(updatedAnnotations) =>
122	                    k8sPatch({
123	                      data: [
124	                        {
125	                          op: 'replace',
126	                          path: '/metadata/annotations',
127	                          value: updatedAnnotations,
128	                        },
129	                      ],
130	                      model: DataSourceModel,
131	                      resource: dataSource,
132	                    })
133	                  }
134	                  isOpen={isOpen}
135	                  obj={dataSource}
136	                  onClose={onClose}
137	                />
138	              ))
139	            }
140	            breadcrumb="DataSource.metadata.annotations"
141	            descriptionHeader={t('Annotations')}
142	            isEdit
143	            isPopover
144	            moreInfoURL={documentationURL.ANNOTATIONS}
145	          />
146	          <VirtualMachineDescriptionItem
147	            // body-content text copied from: https://github.com/kubevirt-ui/kubevirt-api/blob/main/containerized-data-importer/models/V1ObjectMeta.ts#L84
148	            bodyContent={t(
149	              'Time is a wrapper around time.Time which supports correct marshaling to YAML and JSON.  Wrappers are provided for many of the factory methods that the time package offers.',
150	            )}
151	            breadcrumb="DataSource.metadata.creationTimestamp"
152	            descriptionData={<Timestamp timestamp={dataSource?.metadata?.creationTimestamp} />}
153	            descriptionHeader={t('Created at')}
154	            isPopover
155	          />
156	          <OwnerDetailsItem obj={dataSource} />
157	        </DescriptionList>
158	      </GridItem>
159	      <GridItem span={1} />
160	      <GridItem span={5}>
161	        <DescriptionList className="pf-v6-c-description-list">
162	          {dataImportCron && (
163	            <DataSourceImportCronDescription
164	              dataImportCronName={dataImportCron}
165	              namespace={dataSource?.metadata?.namespace}
166	            />
167	          )}
168	          {pvcSourceName && pvcSourceNamespace && (
169	            <VirtualMachineDescriptionItem
170	              descriptionData={
171	                <ResourceLink
172	                  kind={PersistentVolumeClaimModel.kind}
173	                  name={pvcSourceName}
174	                  namespace={pvcSourceNamespace}
175	                />
176	              }
177	              descriptionHeader={t('Source')}
178	            />
179	          )}
180	          <VirtualMachineDescriptionItem
181	            descriptionData={
182	              <ResourceLink
183	                groupVersionKind={VirtualMachineClusterInstancetypeModelGroupVersionKind}
184	                name={getLabel(dataSource, DEFAULT_INSTANCETYPE_LABEL)}
185	              />
186	            }
187	            bodyContent={t('The default InstanceType for this volume.')}
188	            descriptionHeader={t('Default InstanceType')}
189	            isPopover
190	          />
191	          <VirtualMachineDescriptionItem
192	            descriptionData={
193	              <ResourceLink
194	                groupVersionKind={VirtualMachineClusterPreferenceModelGroupVersionKind}
195	                name={getLabel(dataSource, DEFAULT_PREFERENCE_LABEL)}
196	              />
197	            }
198	            bodyContent={<PreferencePopoverContent />}
199	            descriptionHeader={t('Preference')}
200	            isPopover
201	          />
202	        </DescriptionList>
203	      </GridItem>
204	    </Grid>
205	  );
206	};

