  1	import React, { FC, ReactNode } from 'react';
  2	
  3	import { DescriptionItemHeader } from '@kubevirt-utils/components/DescriptionItem/DescriptionItemHeader';
  4	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
  5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  6	import {
  7	  Button,
  8	  DescriptionListDescription,
  9	  DescriptionListGroup,
 10	  DescriptionListTermHelpText,
 11	  Flex,
 12	  FlexItem,
 13	} from '@patternfly/react-core';
 14	import { PencilAltIcon } from '@patternfly/react-icons';
 15	
 16	import EditButtonWithTooltip from './EditButtonWithTooltip';
 17	
 18	import './VirtualMachineDescriptionItem.scss';
 19	
 20	type VirtualMachineDescriptionItemProps = {
 21	  bodyContent?: ReactNode;
 22	  breadcrumb?: string;
 23	  className?: string;
 24	  'data-test-id'?: string;
 25	  descriptionData: any;
 26	  descriptionHeader?: ReactNode;
 27	  editOnTitleJustify?: boolean;
 28	  isDisabled?: boolean;
 29	  isEdit?: boolean;
 30	  isPopover?: boolean;
 31	  label?: ReactNode;
 32	  messageOnDisabled?: string;
 33	  moreInfoURL?: string;
 34	  onEditClick?: () => void;
 35	  showEditOnTitle?: boolean;
 36	  subTitle?: string;
 37	};
 38	
 39	const VirtualMachineDescriptionItem: FC<VirtualMachineDescriptionItemProps> = ({
 40	  bodyContent,
 41	  breadcrumb,
 42	  className,
 43	  'data-test-id': testId,
 44	  descriptionData,
 45	  descriptionHeader,
 46	  editOnTitleJustify = false,
 47	  isDisabled,
 48	  isEdit,
 49	  isPopover,
 50	  label,
 51	  messageOnDisabled,
 52	  moreInfoURL,
 53	  onEditClick,
 54	  showEditOnTitle,
 55	  subTitle,
 56	}) => {
 57	  const { t } = useKubevirtTranslation();
 58	  const NotAvailable = <MutedTextSpan text={t('Not available')} />;
 59	
 60	  const description = (
 61	    <EditButtonWithTooltip
 62	      isEditable={!isDisabled}
 63	      onEditClick={onEditClick}
 64	      testId={testId}
 65	      tooltipContent={messageOnDisabled}
 66	    >
 67	      {descriptionData ?? NotAvailable}
 68	    </EditButtonWithTooltip>
 69	  );
 70	
 71	  return (
 72	    <DescriptionListGroup className={`pf-v6-c-description-list__group ${className && className}`}>
 73	      <DescriptionListTermHelpText className="pf-v6-c-description-list__term">
 74	        <Flex
 75	          justifyContent={{
 76	            default: editOnTitleJustify ? 'justifyContentSpaceBetween' : 'justifyContentFlexStart',
 77	          }}
 78	        >
 79	          {(bodyContent || breadcrumb || descriptionHeader || label || moreInfoURL) && (
 80	            <FlexItem>
 81	              <DescriptionItemHeader
 82	                bodyContent={bodyContent}
 83	                breadcrumb={breadcrumb}
 84	                descriptionHeader={descriptionHeader}
 85	                isPopover={isPopover}
 86	                label={label}
 87	                moreInfoURL={moreInfoURL}
 88	              />
 89	            </FlexItem>
 90	          )}
 91	          {isEdit && showEditOnTitle && (
 92	            <FlexItem>
 93	              <Button
 94	                data-test-id={`${testId}-edit`}
 95	                icon={<PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />}
 96	                isDisabled={isDisabled}
 97	                isInline
 98	                onClick={onEditClick}
 99	                type="button"
100	                variant="link"
101	              >
102	                {t('Edit')}
103	              </Button>
104	            </FlexItem>
105	          )}
106	        </Flex>
107	      </DescriptionListTermHelpText>
108	
109	      <DescriptionListDescription
110	        className="pf-v6-c-description-list__description"
111	        data-test-id={testId}
112	      >
113	        {subTitle && <div className="pf-v6-c-description-list__text pf-v6-u-my-sm">{subTitle}</div>}
114	        {isEdit && !showEditOnTitle ? description : descriptionData}
115	      </DescriptionListDescription>
116	    </DescriptionListGroup>
117	  );
118	};
119	
120	export default VirtualMachineDescriptionItem;

